using System.ComponentModel;
using System.Text;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient.
/// Uses constructor injection — the SDK resolves HttpClient from DI
/// and does NOT expose it in the tool schema.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all items from the API. Returns a JSON array.")]
    public async Task<string> ListItems(
        [Description("Maximum number of items to return (1-100, default 20)")] int limit = 20,
        [Description("Number of items to skip for pagination")] int offset = 0,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing items (limit={Limit}, offset={Offset})", limit, offset);

        limit = Math.Clamp(limit, 1, 100);
        var response = await httpClient.GetAsync($"/items?limit={limit}&offset={offset}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Get a single item by its unique identifier. Returns JSON.")]
    public async Task<string> GetItem(
        [Description("The unique identifier of the item to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Getting item {Id}", id);

        var response = await httpClient.GetAsync($"/items/{Uri.EscapeDataString(id)}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Create a new item. Returns the created item as JSON.")]
    public async Task<string> CreateItem(
        [Description("Display name for the new item")] string name,
        [Description("Optional description of the item")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating item with name={Name}", name);

        var payload = JsonSerializer.Serialize(new { name, description }, JsonOptions);
        var content = new StringContent(payload, Encoding.UTF8, "application/json");
        var response = await httpClient.PostAsync("/items", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Search items by keyword. Returns matching items as a JSON array.")]
    public async Task<string> SearchItems(
        [Description("Search query to match against item names and descriptions")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching items with query={Query}", query);

        var encoded = Uri.EscapeDataString(query);
        var response = await httpClient.GetAsync($"/items/search?q={encoded}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

