         logger.LogInformation("Searching items with query={Query}", query);

         var encoded = Uri.EscapeDataString(query);
         var response = await httpClient.GetAsync($"/items/search?q={encoded}", cancellationToken);
         response.EnsureSuccessStatusCode();
         return await response.Content.ReadAsStringAsync(cancellationToken);
     }
 }
